  useCallback,
  useRef,
  useState,
} from 'react';
import { ChevronDown, Home } from 'lucide-react';
import {
  alignmentForPick,
  compassLabelFromAzimuth,
  type ViewCubeAlignment,
  type ViewCubeCorner,
  type ViewCubeEdge,
  type ViewCubeFace,
  type ViewCubePick,
} from './viewCubeAlignment';

/**
 * ViewCube widget — spec §15.4.
 *
 * Compact isometric cube sitting top-right of the 3D canvas. Faces +
 * top corners are clickable (snap camera to that alignment). The cube
 * also supports drag-to-orbit: dragging anywhere on the stage orbits
 * the main camera live via the `onDrag` callback.
 *
 * The compass tracks camera azimuth; the cube visual stays recognizably
 * three-dimensional like Revit's widget instead of flattening at cardinal
 * camera poses.
 */

export interface ViewCubeProps {
  currentAzimuth: number;
  /** Camera elevation in radians (0 = horizontal, π/2 = straight down). */
  currentElevation: number;
  onPick: (pick: ViewCubePick, alignment: ViewCubeAlignment) => void;
  /** Raw pixel deltas during a drag. Viewport calls rig.orbit(dx, dy). */
  onDrag?: (dxPx: number, dyPx: number) => void;
  /** Optional className for positioning. */
  className?: string;
}

const CUBE_WIDTH_PX = 94;
const CUBE_HEIGHT_PX = 90;
const DRAG_THRESHOLD_PX = 4;

const TOP_CORNERS: { id: ViewCubeCorner; left: string; top: string }[] = [
  { id: 'TOP-NW', left: '22px', top: '23px' },
  { id: 'TOP-NE', left: '72px', top: '24px' },
  { id: 'TOP-SW', left: '29px', top: '48px' },
  { id: 'TOP-SE', left: '74px', top: '49px' },
];

interface FaceDef {
  id: ViewCubeFace;
  label: string;
  left: number;
  top: number;
  width: number;
  height: number;
}

interface EdgeDef {
  id: ViewCubeEdge;
  label: string;
  left: number;
  top: number;
  width: number;
  height: number;
}

const FACES: FaceDef[] = [
  { id: 'TOP', label: 'TOP', left: 18, top: 0, width: 60, height: 36 },
  { id: 'FRONT', label: 'FRONT', left: 2, top: 24, width: 48, height: 62 },
  { id: 'RIGHT', label: 'RIGHT', left: 48, top: 24, width: 44, height: 62 },
  { id: 'BACK', label: 'BACK', left: 52, top: 0, width: 26, height: 28 },
  { id: 'LEFT', label: 'LEFT', left: 2, top: 22, width: 24, height: 34 },
  { id: 'BOTTOM', label: 'BASE', left: 28, top: 64, width: 42, height: 24 },
];

const EDGES: EdgeDef[] = [
  { id: 'FRONT-TOP', label: 'Front top edge', left: 13, top: 24, width: 46, height: 12 },
  { id: 'RIGHT-TOP', label: 'Right top edge', left: 45, top: 24, width: 39, height: 12 },
  { id: 'LEFT-TOP', label: 'Left top edge', left: 8, top: 17, width: 44, height: 12 },
  { id: 'BACK-TOP', label: 'Back top edge', left: 42, top: 9, width: 44, height: 12 },
  { id: 'FRONT-RIGHT', label: 'Front right edge', left: 43, top: 34, width: 14, height: 50 },
  { id: 'FRONT-LEFT', label: 'Front left edge', left: 4, top: 31, width: 14, height: 45 },
  { id: 'BACK-RIGHT', label: 'Back right edge', left: 78, top: 26, width: 14, height: 46 },
  { id: 'BACK-LEFT', label: 'Back left edge', left: 43, top: 7, width: 14, height: 35 },
];

export function ViewCube({
  currentAzimuth,
  currentElevation: _currentElevation,
  onPick,
  onDrag,
  className,
}: ViewCubeProps): JSX.Element {
  const dragRef = useRef({ dragging: false, totalMoved: 0 });
  const suppressNextClickRef = useRef(false);
  const [isDragging, setIsDragging] = useState(false);

  function emit(pick: ViewCubePick): void {
    onPick(pick, alignmentForPick(pick));
  }

  function handleKey(event: KeyboardEvent<HTMLDivElement>): void {
    if (event.key === 'Enter' || event.key === ' ') {
      event.preventDefault();
      emit({ kind: 'home' });
    }
  }

  const handlePointerDown = useCallback(
    (e: React.PointerEvent<HTMLDivElement>) => {
      if (e.button !== 0) return;
      dragRef.current = { dragging: true, totalMoved: 0 };
      setIsDragging(true);
      document.body.style.cursor = 'grabbing';

      const onMove = (ev: PointerEvent) => {
        const dx = ev.movementX;
        const dy = ev.movementY;
        dragRef.current.totalMoved += Math.abs(dx) + Math.abs(dy);
        onDrag?.(dx, dy);
      };

      const onUp = () => {
        if (dragRef.current.totalMoved > DRAG_THRESHOLD_PX) {
          suppressNextClickRef.current = true;
        }
        dragRef.current.dragging = false;
        setIsDragging(false);
        document.body.style.cursor = '';
        window.removeEventListener('pointermove', onMove);
        window.removeEventListener('pointerup', onUp);
      };

      window.addEventListener('pointermove', onMove);
      window.addEventListener('pointerup', onUp);
    },
    [onDrag],
  );

  const handleClickCapture = useCallback((e: React.MouseEvent) => {
    if (suppressNextClickRef.current) {
      e.stopPropagation();
      suppressNextClickRef.current = false;
    }
  }, []);

  const stageStyle: CSSProperties = {
    width: CUBE_WIDTH_PX,
    height: CUBE_HEIGHT_PX,
    position: 'relative',
    cursor: isDragging ? 'grabbing' : 'grab',
    zIndex: 2,
  };

  return (
    <div
      data-testid="view-cube"
      role="group"
      aria-label="ViewCube"
      onKeyDown={handleKey}
      className={['group relative flex items-center justify-center', className ?? ''].join(' ')}
      style={{ width: 150, height: 148 }}
    >
      <button
        type="button"
        onClick={() => emit({ kind: 'home' })}
        aria-label="Reset camera to home view"
        title="Home view"
        className="absolute left-1 top-0 flex h-7 w-7 items-center justify-center rounded-sm text-muted transition hover:bg-surface hover:text-foreground focus-visible:outline focus-visible:outline-2 focus-visible:outline-accent"
      >
        <Home size={20} strokeWidth={1.9} aria-hidden="true" />
      </button>

      <ViewCubeCompass currentAzimuth={currentAzimuth} />

      {/* Stage: drag here to orbit; click a face/corner to snap. */}
      <div
        data-testid="view-cube-stage"
        style={stageStyle}
        onPointerDown={handlePointerDown}
        onClickCapture={handleClickCapture}
      >
        <CubeVisual />

        {FACES.map((face) => (
          <CubeFace
            key={face.id}
            face={face}
            onClick={() => emit({ kind: 'face', face: face.id })}
          />
        ))}
        {EDGES.map((edge) => (
          <CubeEdge
            key={edge.id}
            edge={edge}
            onClick={() => emit({ kind: 'edge', edge: edge.id })}
          />
        ))}

        {/* Corner snap targets: Revit-like blue grips appear when hovering the cube. */}
        {TOP_CORNERS.map((c) => (
          <button
            key={c.id}
            type="button"
            onClick={() => emit({ kind: 'corner', corner: c.id })}
            aria-label={`Align camera to ${c.id}`}
            data-corner={c.id}
            style={{
              position: 'absolute',
              left: c.left,
              top: c.top,
              transform: 'translate(-50%, -50%)',
              width: 12,
              height: 12,
              borderRadius: 2,
              border: 0,
              background: 'transparent',
              cursor: 'pointer',
              padding: 0,
              zIndex: 4,
            }}
            className="focus-visible:outline focus-visible:outline-2 focus-visible:outline-accent"
          />
        ))}
      </div>

      <button
        type="button"
        onClick={() => emit({ kind: 'face', face: 'BOTTOM' })}
        aria-label="Look from below"
        title="Look from below"
        className="absolute right-0 top-[84px] flex h-7 w-7 items-center justify-center rounded-sm text-muted transition hover:bg-surface hover:text-foreground focus-visible:outline focus-visible:outline-2 focus-visible:outline-accent"
      >
        <ChevronDown size={22} strokeWidth={1.8} aria-hidden="true" />
      </button>
    </div>
  );
}

function CubeVisual(): JSX.Element {
  return (
    <svg
      data-cube-stage="true"
      aria-hidden="true"
      viewBox="0 0 94 90"
      width={CUBE_WIDTH_PX}
      height={CUBE_HEIGHT_PX}
      className="pointer-events-none absolute inset-0 overflow-visible"
      style={{ filter: 'drop-shadow(0 15px 13px rgba(15, 23, 42, 0.22))' }}
    >
      <polygon
        points="47,4 88,23 49,42 8,23"
        fill="color-mix(in srgb, var(--color-surface) 94%, white 6%)"
        stroke="color-mix(in srgb, var(--color-border) 68%, var(--color-foreground) 32%)"
        strokeWidth="1.5"
      />
      <polygon
        points="8,23 49,42 49,84 8,63"
        fill="color-mix(in srgb, var(--color-surface) 87%, var(--color-foreground) 13%)"
        stroke="color-mix(in srgb, var(--color-border) 68%, var(--color-foreground) 32%)"
        strokeWidth="1.5"
      />
      <polygon
        points="49,42 88,23 88,64 49,84"
        fill="color-mix(in srgb, var(--color-surface) 80%, var(--color-foreground) 20%)"
        stroke="color-mix(in srgb, var(--color-border) 68%, var(--color-foreground) 32%)"
        strokeWidth="1.5"
      />
      <polyline
        points="8,23 49,42 88,23"
        fill="none"
        stroke="rgba(255,255,255,0.72)"
        strokeWidth="1"
      />
      <text
        x="48"
        y="25"
        textAnchor="middle"
        dominantBaseline="middle"
        transform="rotate(24 48 25)"
        fill="color-mix(in srgb, var(--color-foreground) 76%, #64748b 24%)"
        fontFamily="Arial, Helvetica, sans-serif"
        fontSize="8.5"
        fontWeight="700"
        letterSpacing="0.2"
      >
        TOP
      </text>
      <text
        x="28"
        y="59"
        textAnchor="middle"
        dominantBaseline="middle"
        fill="color-mix(in srgb, var(--color-foreground) 76%, #64748b 24%)"
        fontFamily="Arial, Helvetica, sans-serif"
        fontSize="8.25"
        fontWeight="700"
        letterSpacing="0.1"
      >
        FRONT
      </text>
      <text
        x="70"
        y="58"
        textAnchor="middle"
        dominantBaseline="middle"
        fill="color-mix(in srgb, var(--color-foreground) 76%, #64748b 24%)"
        fontFamily="Arial, Helvetica, sans-serif"
        fontSize="8.25"
        fontWeight="700"
        letterSpacing="0.1"
      >
        RIGHT
      </text>
    </svg>
  );
}

function CubeFace({ face, onClick }: { face: FaceDef; onClick: () => void }): JSX.Element {
  const style: CSSProperties = {
    position: 'absolute',
    left: face.left,
    top: face.top,
    width: face.width,
    height: face.height,
    background: 'transparent',
    border: 0,
    borderRadius: 3,
    cursor: 'grab',
    padding: 0,
    zIndex: 3,
  };

  return (
    <button
      type="button"
      onClick={onClick}
      aria-label={`Align camera to ${face.id}`}
      data-face={face.id}
      style={style}
      title={`Align camera to ${face.label}`}
      className="hover:bg-accent/10 focus-visible:outline focus-visible:outline-2 focus-visible:outline-accent"
    />
  );
}

function CubeEdge({ edge, onClick }: { edge: EdgeDef; onClick: () => void }): JSX.Element {
  const style: CSSProperties = {
    position: 'absolute',
    left: edge.left,
    top: edge.top,
    width: edge.width,
    height: edge.height,
    border: '1px solid color-mix(in srgb, var(--color-accent) 78%, white 22%)',
    background: 'color-mix(in srgb, var(--color-accent) 18%, transparent)',
    boxShadow: 'inset 0 0 0 1px rgba(255,255,255,0.45)',
    borderRadius: 2,
    cursor: 'grab',
    opacity: 0,
    padding: 0,
    backfaceVisibility: 'hidden',
    transition: 'opacity 130ms, background 130ms',
  };

  return (
    <button
      type="button"
      onClick={onClick}
      aria-label={`Align camera to ${edge.id}`}
      data-edge={edge.id}
      title={edge.label}
      style={style}
      className="group-hover:opacity-60 hover:!opacity-100 hover:!bg-accent/25"
    />
  );
}

function ViewCubeCompass({ currentAzimuth }: { currentAzimuth: number }): JSX.Element {
  const cardinal = compassLabelFromAzimuth(currentAzimuth);

  return (
    <div
      data-testid="view-cube-compass"
      data-cardinal={cardinal}
      className="pointer-events-none absolute left-1/2 top-[32px] h-[102px] w-[126px] -translate-x-1/2"
      aria-hidden="true"
    >
      <div className="absolute left-1/2 top-[36px] h-[58px] w-[112px] -translate-x-1/2 rounded-[50%] border border-dashed border-slate-400/65" />
      <div
        className="absolute left-[7px] top-[62px] h-5 w-5 rounded-full border border-slate-400/70 bg-surface/80 text-center text-[14px] font-bold leading-5 text-slate-500"
        style={{ letterSpacing: 0 }}
      >
        S
      </div>
      <div
        className="absolute right-[7px] top-[62px] h-5 w-5 rounded-full border border-slate-400/70 bg-surface/80 text-center text-[14px] font-bold leading-5 text-slate-500"
        style={{ letterSpacing: 0 }}
      >
        E
      </div>
      <div
        className="absolute left-[21px] top-[30px] text-[14px] font-bold text-slate-500"
        style={{ letterSpacing: 0 }}
      >
        W
      </div>
      <div
        className="absolute right-[21px] top-[30px] text-[14px] font-bold text-slate-500"
        style={{ letterSpacing: 0 }}
      >
        N
      </div>
      <div className="absolute left-[26px] top-[49px] h-2 w-2 rotate-[-35deg] border-l-2 border-t-2 border-slate-400/80" />
      <div className="absolute right-[26px] top-[49px] h-2 w-2 rotate-[145deg] border-l-2 border-t-2 border-slate-400/80" />
    </div>
  );
}

