  F: { x: 1, y: -1, z: 1 },
  G: { x: 1, y: -1, z: -1 },
  H: { x: -1, y: -1, z: -1 },
};

const FACE_VERTICES: Record<ViewCubeFace, string[]> = {
  TOP: ['D', 'C', 'B', 'A'],
  FRONT: ['A', 'B', 'F', 'E'],
  RIGHT: ['B', 'C', 'G', 'F'],
  BACK: ['C', 'D', 'H', 'G'],
  LEFT: ['D', 'A', 'E', 'H'],
  BOTTOM: ['E', 'F', 'G', 'H'],
};

const FACE_NORMALS: Record<ViewCubeFace, Vec3> = {
  TOP: { x: 0, y: 1, z: 0 },
  FRONT: { x: 0, y: 0, z: 1 },
  RIGHT: { x: 1, y: 0, z: 0 },
  BACK: { x: 0, y: 0, z: -1 },
  LEFT: { x: -1, y: 0, z: 0 },
  BOTTOM: { x: 0, y: -1, z: 0 },
};

const FACE_LABELS: Record<ViewCubeFace, string> = {
  TOP: 'TOP',
  FRONT: 'BACK',
  RIGHT: 'LEFT',
  BACK: 'FRONT',
  LEFT: 'RIGHT',
  BOTTOM: 'BASE',
};

const EDGE_VERTICES: Record<ViewCubeEdge, [string, string]> = {
  'FRONT-TOP': ['A', 'B'],
  'BACK-TOP': ['C', 'D'],
  'LEFT-TOP': ['D', 'A'],
  'RIGHT-TOP': ['B', 'C'],
  'FRONT-BOTTOM': ['E', 'F'],
  'BACK-BOTTOM': ['G', 'H'],
  'LEFT-BOTTOM': ['H', 'E'],
  'RIGHT-BOTTOM': ['F', 'G'],
  'FRONT-LEFT': ['A', 'E'],
  'FRONT-RIGHT': ['B', 'F'],
  'BACK-LEFT': ['D', 'H'],
  'BACK-RIGHT': ['C', 'G'],
};

const CORNER_VERTICES: Record<ViewCubeCorner, string> = {
  'TOP-NW': 'D',
  'TOP-NE': 'C',
  'TOP-SW': 'A',
  'TOP-SE': 'B',
  'BOTTOM-NW': 'H',
  'BOTTOM-NE': 'G',
  'BOTTOM-SW': 'E',
  'BOTTOM-SE': 'F',
};

function CubeVisual({
  visualAzimuthDelta,
  currentElevation,
  hoverTarget,
}: {
  visualAzimuthDelta: number;
  currentElevation: number;
  hoverTarget: HoverTarget;
}): JSX.Element {
  const projection = projectCube(visualAzimuthDelta, currentElevation);
  const hoveredFace =
    hoverTarget?.kind === 'face'
      ? projection.faces.find((face) => face.id === hoverTarget.face)
      : null;
  const hoveredEdge =
    hoverTarget?.kind === 'edge' ? projection.edges[hoverTarget.edge] : undefined;
  const hoveredCorner =
    hoverTarget?.kind === 'corner' ? projection.corners[hoverTarget.corner] : undefined;

  return (
    <svg
      data-cube-stage="true"
      aria-hidden="true"
      viewBox="0 0 94 90"
      width={CUBE_WIDTH_PX}
      height={CUBE_HEIGHT_PX}
      className="pointer-events-none absolute inset-0 overflow-visible"
      style={{ filter: 'drop-shadow(0 15px 13px rgba(15, 23, 42, 0.22))' }}
    >
      {projection.faces.map((face) => (
        <polygon
          key={face.id}
          points={pointsAttr(face.points)}
          fill={faceFill(face.id)}
          stroke="color-mix(in srgb, var(--color-border) 68%, var(--color-foreground) 32%)"
          strokeWidth="1.5"
        />
      ))}
      {hoveredFace ? (
        <polygon
          points={pointsAttr(hoveredFace.points)}
          fill="color-mix(in srgb, var(--color-accent) 23%, transparent)"
          stroke="color-mix(in srgb, var(--color-accent) 90%, white 10%)"
          strokeWidth="2"
        />
      ) : null}
      {hoveredEdge ? (
        <line
          x1={hoveredEdge[0].x}
          y1={hoveredEdge[0].y}
          x2={hoveredEdge[1].x}
          y2={hoveredEdge[1].y}
          stroke="color-mix(in srgb, var(--color-accent) 88%, white 12%)"
          strokeWidth="4"
          strokeLinecap="round"
        />
      ) : null}
      {hoveredCorner ? (
        <rect
          x={hoveredCorner.x - 5}
          y={hoveredCorner.y - 5}
          width="10"
          height="10"
          rx="2"
          fill="color-mix(in srgb, var(--color-accent) 24%, transparent)"
          stroke="color-mix(in srgb, var(--color-accent) 88%, white 12%)"
          strokeWidth="1.5"
        />
      ) : null}
      {projection.faces.map((face) => (
        <text
          key={`${face.id}-label`}
          x={face.center.x}
          y={face.center.y + labelYOffset(face.id)}
          textAnchor="middle"
          dominantBaseline="middle"
          transform={face.id === 'TOP' ? `rotate(24 ${face.center.x} ${face.center.y})` : undefined}
          fill="color-mix(in srgb, var(--color-foreground) 76%, #64748b 24%)"
          fontFamily="Arial, Helvetica, sans-serif"
          fontSize={face.id === 'TOP' ? '8.5' : '8.25'}
          fontWeight="700"
          letterSpacing="0.1"
        >
          {face.label}
        </text>
      ))}
    </svg>
  );
}

function projectCube(visualAzimuthDelta: number, currentElevation: number) {
  const yaw = -visualAzimuthDelta - Math.PI / 4;
  const pitch = Math.max(0.34, Math.min(0.74, 0.44 + (currentElevation - 0.45) * 0.18));
  const projectedVertices = Object.fromEntries(
    Object.entries(CUBE_VERTICES).map(([key, vertex]) => [key, projectPoint(vertex, yaw, pitch)]),
  ) as Record<string, ProjectedPoint>;

  const faces = (Object.keys(FACE_VERTICES) as ViewCubeFace[])
    .map((id) => {
      const normal = rotatePoint(FACE_NORMALS[id], yaw, pitch);
      const points = FACE_VERTICES[id].map((key) => projectedVertices[key]!);
      return {
        id,
        label: FACE_LABELS[id],
        points,
        depth: average(points.map((point) => point.depth)),
        center: {
          x: average(points.map((point) => point.x)),
          y: average(points.map((point) => point.y)),
          depth: average(points.map((point) => point.depth)),
        },
        visible: normal.z > 0.06,
      };
    })
    .filter((face): face is ProjectedFace & { visible: true } => face.visible)
    .sort((a, b) => a.depth - b.depth);

  const edges = Object.fromEntries(
    Object.entries(EDGE_VERTICES).map(([edge, [a, b]]) => [
      edge,
      [projectedVertices[a]!, projectedVertices[b]!] as [ProjectedPoint, ProjectedPoint],
    ]),
  ) as Record<ViewCubeEdge, [ProjectedPoint, ProjectedPoint]>;

  const corners = Object.fromEntries(
    Object.entries(CORNER_VERTICES).map(([corner, vertex]) => [corner, projectedVertices[vertex]!]),
  ) as Record<ViewCubeCorner, ProjectedPoint>;

  return { faces, edges, corners };
}

function projectPoint(point: Vec3, yaw: number, pitch: number): ProjectedPoint {
  const rotated = rotatePoint(point, yaw, pitch);
  const scale = 28;
  return {
    x: 47 + rotated.x * scale,
    y: 45 - rotated.y * scale,
    depth: rotated.z,
  };
}

function rotatePoint(point: Vec3, yaw: number, pitch: number): Vec3 {
  const cosY = Math.cos(yaw);
  const sinY = Math.sin(yaw);
  const x1 = cosY * point.x + sinY * point.z;
  const z1 = -sinY * point.x + cosY * point.z;
  const cosX = Math.cos(pitch);
  const sinX = Math.sin(pitch);
  return {
    x: x1,
    y: cosX * point.y - sinX * z1,
    z: sinX * point.y + cosX * z1,
  };
}

function average(values: number[]): number {
  return values.reduce((sum, value) => sum + value, 0) / values.length;
}

function pointsAttr(points: ProjectedPoint[]): string {
  return points.map((point) => `${point.x.toFixed(1)},${point.y.toFixed(1)}`).join(' ');
}

function faceFill(face: ViewCubeFace): string {
  if (face === 'TOP') return 'color-mix(in srgb, var(--color-surface) 94%, white 6%)';
  if (face === 'RIGHT' || face === 'BACK') {
    return 'color-mix(in srgb, var(--color-surface) 80%, var(--color-foreground) 20%)';
  }
  return 'color-mix(in srgb, var(--color-surface) 87%, var(--color-foreground) 13%)';
}

function labelYOffset(face: ViewCubeFace): number {
  return face === 'TOP' ? -1 : 2;
}

function CubeFace({
  face,
  onClick,
  onHover,
}: {
  face: FaceDef;
  onClick: () => void;
  onHover: (hovered: boolean) => void;
}): JSX.Element {
  const style: CSSProperties = {
    position: 'absolute',
    left: face.left,
    top: face.top,
    width: face.width,
    height: face.height,
    background: 'transparent',
    border: 0,
    borderRadius: 3,
    cursor: 'grab',
    padding: 0,
    zIndex: 3,
  };

  return (
    <button
      type="button"
      onClick={onClick}
      onPointerEnter={() => onHover(true)}
      onPointerLeave={() => onHover(false)}
      aria-label={`Align camera to ${face.id}`}
      data-face={face.id}
      style={style}
      title={`Align camera to ${face.label}`}
      className="hover:bg-accent/10 focus-visible:outline focus-visible:outline-2 focus-visible:outline-accent"
    />
  );
}

function CubeEdge({
  edge,
  onClick,
  onHover,
}: {
  edge: EdgeDef;
  onClick: () => void;
  onHover: (hovered: boolean) => void;
}): JSX.Element {
  const style: CSSProperties = {
    position: 'absolute',
    left: edge.left,
    top: edge.top,
    width: edge.width,
    height: edge.height,
    border: 0,
    background: 'transparent',
    borderRadius: 2,
    cursor: 'grab',
    padding: 0,
    backfaceVisibility: 'hidden',
    zIndex: 5,
  };

  return (
    <button
      type="button"
      onClick={onClick}
      onPointerEnter={() => onHover(true)}
      onPointerLeave={() => onHover(false)}
      aria-label={`Align camera to ${edge.id}`}
      data-edge={edge.id}
      title={edge.label}
      style={style}
      className="focus-visible:outline focus-visible:outline-2 focus-visible:outline-accent"
    />
  );
}

function ViewCubeCompass({ currentAzimuth }: { currentAzimuth: number }): JSX.Element {
  const cardinal = compassLabelFromAzimuth(currentAzimuth);

  return (
    <div
      data-testid="view-cube-compass"
      data-cardinal={cardinal}
      className="pointer-events-none absolute left-1/2 top-[32px] h-[102px] w-[126px] -translate-x-1/2"

