import {
  type CSSProperties,
  type JSX,
  type KeyboardEvent,
  useCallback,
  useRef,
  useState,
} from 'react';
import { ChevronDown, Home } from 'lucide-react';
import {
  alignmentForPick,
  compassLabelFromAzimuth,
  type ViewCubeAlignment,
  type ViewCubeCorner,
  type ViewCubeEdge,
  type ViewCubeFace,
  type ViewCubePick,
} from './viewCubeAlignment';

/**
 * ViewCube widget — spec §15.4.
 *
 * Compact CSS-3D cube sitting top-right of the 3D canvas. Faces +
 * top corners are clickable (snap camera to that alignment). The cube
 * also supports drag-to-orbit: dragging anywhere on the stage orbits
 * the main camera live via the `onDrag` callback.
 *
 * The compass tracks camera azimuth; the cube visual uses a Revit-like
 * axonometric presentation and rotates relative to the camera without
 * collapsing into a flat front-on panel.
 */

export interface ViewCubeProps {
  currentAzimuth: number;
  /** Camera elevation in radians (0 = horizontal, π/2 = straight down). */
  currentElevation: number;
  onPick: (pick: ViewCubePick, alignment: ViewCubeAlignment) => void;
  /** Raw pixel deltas during a drag. Viewport calls rig.orbit(dx, dy). */
  onDrag?: (dxPx: number, dyPx: number) => void;
  /** Optional className for positioning. */
  className?: string;
}

const CUBE_SIZE_PX = 66;
const HALF = CUBE_SIZE_PX / 2;
const DRAG_THRESHOLD_PX = 4;

const TOP_CORNERS: { id: ViewCubeCorner; left: string; top: string }[] = [
  { id: 'TOP-NW', left: '9%', top: '9%' },
  { id: 'TOP-NE', left: '91%', top: '9%' },
  { id: 'TOP-SW', left: '9%', top: '91%' },
  { id: 'TOP-SE', left: '91%', top: '91%' },
];

interface FaceDef {
  id: ViewCubeFace;
  label: string;
  transform: string;
  shade: number;
}

type HoverTarget =
  | { kind: 'face'; face: ViewCubeFace }
  | { kind: 'edge'; edge: ViewCubeEdge }
  | { kind: 'corner'; corner: ViewCubeCorner }
  | null;

interface EdgeDef {
  id: ViewCubeEdge;
  label: string;
  width: number;
  height: number;
  transform: string;
}

const FACES: FaceDef[] = [
  { id: 'FRONT', label: 'FRONT', transform: `rotateY(0deg) translateZ(${HALF}px)`, shade: 0.1 },
  { id: 'BACK', label: 'BACK', transform: `rotateY(180deg) translateZ(${HALF}px)`, shade: 0.18 },
  { id: 'RIGHT', label: 'RIGHT', transform: `rotateY(90deg) translateZ(${HALF}px)`, shade: 0.14 },
  { id: 'LEFT', label: 'LEFT', transform: `rotateY(-90deg) translateZ(${HALF}px)`, shade: 0.14 },
  { id: 'TOP', label: 'TOP', transform: `rotateX(90deg) translateZ(${HALF}px)`, shade: 0.04 },
  {
    id: 'BOTTOM',
    label: 'BASE',
    transform: `rotateX(-90deg) translateZ(${HALF}px)`,
    shade: 0.24,
  },
];

const EDGE_THICKNESS_PX = 10;

const EDGES: EdgeDef[] = [
  {
    id: 'FRONT-TOP',
    label: 'Front top edge',
    width: CUBE_SIZE_PX,
    height: EDGE_THICKNESS_PX,
    transform: `translateY(${-HALF + EDGE_THICKNESS_PX / 2}px) translateZ(${HALF + 1}px)`,
  },
  {
    id: 'RIGHT-TOP',
    label: 'Right top edge',
    width: CUBE_SIZE_PX,
    height: EDGE_THICKNESS_PX,
    transform: `rotateY(90deg) translateY(${-HALF + EDGE_THICKNESS_PX / 2}px) translateZ(${HALF + 1}px)`,
  },
  {
    id: 'LEFT-TOP',
    label: 'Left top edge',
    width: CUBE_SIZE_PX,
    height: EDGE_THICKNESS_PX,
    transform: `rotateY(-90deg) translateY(${-HALF + EDGE_THICKNESS_PX / 2}px) translateZ(${HALF + 1}px)`,
  },
  {
    id: 'BACK-TOP',
    label: 'Back top edge',
    width: CUBE_SIZE_PX,
    height: EDGE_THICKNESS_PX,
    transform: `rotateY(180deg) translateY(${-HALF + EDGE_THICKNESS_PX / 2}px) translateZ(${HALF + 1}px)`,
  },
  {
    id: 'FRONT-RIGHT',
    label: 'Front right edge',
    width: EDGE_THICKNESS_PX,
    height: CUBE_SIZE_PX,
    transform: `translateX(${HALF - EDGE_THICKNESS_PX / 2}px) translateZ(${HALF + 1}px)`,
  },
  {
    id: 'FRONT-LEFT',
    label: 'Front left edge',
    width: EDGE_THICKNESS_PX,
    height: CUBE_SIZE_PX,
    transform: `translateX(${-HALF + EDGE_THICKNESS_PX / 2}px) translateZ(${HALF + 1}px)`,
  },
  {
    id: 'BACK-RIGHT',
    label: 'Back right edge',
    width: EDGE_THICKNESS_PX,
    height: CUBE_SIZE_PX,
    transform: `rotateY(180deg) translateX(${-HALF + EDGE_THICKNESS_PX / 2}px) translateZ(${HALF + 1}px)`,
  },
  {
    id: 'BACK-LEFT',
    label: 'Back left edge',
    width: EDGE_THICKNESS_PX,
    height: CUBE_SIZE_PX,
    transform: `rotateY(180deg) translateX(${HALF - EDGE_THICKNESS_PX / 2}px) translateZ(${HALF + 1}px)`,
  },
];

export function ViewCube({
  currentAzimuth,
  currentElevation,
  onPick,
  onDrag,
  className,
}: ViewCubeProps): JSX.Element {
  const dragRef = useRef({ dragging: false, totalMoved: 0 });
  const suppressNextClickRef = useRef(false);
  const initialAzimuthRef = useRef(currentAzimuth);
  const [isDragging, setIsDragging] = useState(false);
  const [hoverTarget, setHoverTarget] = useState<HoverTarget>(null);
  const visualAzimuthDelta = currentAzimuth - initialAzimuthRef.current;

  function emit(pick: ViewCubePick): void {
    onPick(pick, alignmentForPick(pick));
  }

  function handleKey(event: KeyboardEvent<HTMLDivElement>): void {
    if (event.key === 'Enter' || event.key === ' ') {
      event.preventDefault();
      emit({ kind: 'home' });
    }
  }

  const handlePointerDown = useCallback(
    (e: React.PointerEvent<HTMLDivElement>) => {
      if (e.button !== 0) return;
      dragRef.current = { dragging: true, totalMoved: 0 };
      setIsDragging(true);
      document.body.style.cursor = 'grabbing';

      const onMove = (ev: PointerEvent) => {
        const dx = ev.movementX;
        const dy = ev.movementY;
        dragRef.current.totalMoved += Math.abs(dx) + Math.abs(dy);
        onDrag?.(dx, dy);
      };

      const onUp = () => {
        if (dragRef.current.totalMoved > DRAG_THRESHOLD_PX) {
          suppressNextClickRef.current = true;
        }
        dragRef.current.dragging = false;
        setIsDragging(false);
        document.body.style.cursor = '';
        window.removeEventListener('pointermove', onMove);
        window.removeEventListener('pointerup', onUp);
      };

      window.addEventListener('pointermove', onMove);
      window.addEventListener('pointerup', onUp);
    },
    [onDrag],
  );

  const handleClickCapture = useCallback((e: React.MouseEvent) => {
    if (suppressNextClickRef.current) {
      e.stopPropagation();
      suppressNextClickRef.current = false;
    }
  }, []);

  const stageStyle: CSSProperties = {
    width: CUBE_SIZE_PX,
    height: CUBE_SIZE_PX,
    perspective: '360px',
    position: 'relative',
    cursor: isDragging ? 'grabbing' : 'grab',
    zIndex: 2,
  };

  return (
    <div
      data-testid="view-cube"
      role="group"
      aria-label="ViewCube"
      onKeyDown={handleKey}
      className={['group relative flex items-center justify-center', className ?? ''].join(' ')}
      style={{ width: 150, height: 148 }}
    >
      <button
        type="button"
        onClick={() => emit({ kind: 'home' })}
        aria-label="Reset camera to home view"
        title="Home view"
        className="absolute left-1 top-0 flex h-7 w-7 items-center justify-center rounded-sm text-muted transition hover:bg-surface hover:text-foreground focus-visible:outline focus-visible:outline-2 focus-visible:outline-accent"
      >
        <Home size={20} strokeWidth={1.9} aria-hidden="true" />
      </button>

      <ViewCubeCompass currentAzimuth={currentAzimuth} />

      {/* Stage: drag here to orbit; click a face/corner to snap. */}
      <div
        data-testid="view-cube-stage"
        style={stageStyle}
        onPointerDown={handlePointerDown}
        onClickCapture={handleClickCapture}
        onPointerLeave={() => setHoverTarget(null)}
      >
        <CubeVisual
          visualAzimuthDelta={visualAzimuthDelta}
          currentElevation={currentElevation}
          hoverTarget={hoverTarget}
        />

        <div
          style={{
            position: 'absolute',
            inset: 0,
            transformStyle: 'preserve-3d',
            transform: cubeTransformString(visualAzimuthDelta, currentElevation),
            transition: 'transform var(--motion-slow) var(--ease-snap)',
            zIndex: 3,
          }}
        >
          {FACES.map((face) => (
            <CubeFace
              key={face.id}
              face={face}
              onClick={() => emit({ kind: 'face', face: face.id })}
              onHover={(hovered) =>
                setHoverTarget(hovered ? { kind: 'face', face: face.id } : null)
              }
            />
          ))}
          {EDGES.map((edge) => (
            <CubeEdge
              key={edge.id}
              edge={edge}
              onClick={() => emit({ kind: 'edge', edge: edge.id })}
              onHover={(hovered) =>
                setHoverTarget(hovered ? { kind: 'edge', edge: edge.id } : null)
              }
            />
          ))}
        </div>

        {/* Corner snap targets: Revit-like blue grips appear when hovering the cube. */}
        {TOP_CORNERS.map((c) => (
          <button
            key={c.id}
            type="button"
            onClick={() => emit({ kind: 'corner', corner: c.id })}
            onPointerEnter={() => setHoverTarget({ kind: 'corner', corner: c.id })}
            onPointerLeave={() => setHoverTarget(null)}
            aria-label={`Align camera to ${c.id}`}
            data-corner={c.id}
            style={{
              position: 'absolute',
              left: c.left,
              top: c.top,
              transform: 'translate(-50%, -50%)',
              width: 12,
              height: 12,
              borderRadius: 2,
              border: 0,
              background: 'transparent',
              cursor: 'pointer',
              padding: 0,
              zIndex: 6,
            }}
            className="focus-visible:outline focus-visible:outline-2 focus-visible:outline-accent"
          />
        ))}
      </div>

      <button
        type="button"
        onClick={() => emit({ kind: 'face', face: 'BOTTOM' })}
        aria-label="Look from below"
        title="Look from below"
        className="absolute right-0 top-[84px] flex h-7 w-7 items-center justify-center rounded-sm text-muted transition hover:bg-surface hover:text-foreground focus-visible:outline focus-visible:outline-2 focus-visible:outline-accent"
      >
        <ChevronDown size={22} strokeWidth={1.8} aria-hidden="true" />
      </button>
    </div>
  );
}

function CubeVisual({
  visualAzimuthDelta,
  currentElevation,
  hoverTarget,
}: {
  visualAzimuthDelta: number;
  currentElevation: number;
  hoverTarget: HoverTarget;
}): JSX.Element {
  const cubeStyle: CSSProperties = {
    position: 'absolute',
    inset: 0,
    transformStyle: 'preserve-3d',
    transform: cubeTransformString(visualAzimuthDelta, currentElevation),
    transition: 'transform var(--motion-slow) var(--ease-snap)',
    filter: 'drop-shadow(0 15px 13px rgba(15, 23, 42, 0.22))',
  };

  return (
    <div
      data-cube-stage="true"
      aria-hidden="true"
      className="pointer-events-none absolute inset-0"
      style={cubeStyle}
    >
      {FACES.map((face) => (
        <CubeVisualFace
          key={face.id}
          face={face}
          active={hoverTarget?.kind === 'face' && hoverTarget.face === face.id}
        />
      ))}
      {EDGES.map((edge) => (
        <CubeVisualEdge
          key={edge.id}
          edge={edge}
          active={hoverTarget?.kind === 'edge' && hoverTarget.edge === edge.id}
        />
      ))}
      {hoverTarget?.kind === 'corner' ? (
        <div
          style={{
            position: 'absolute',
            left: TOP_CORNERS.find((corner) => corner.id === hoverTarget.corner)?.left ?? '50%',
            top: TOP_CORNERS.find((corner) => corner.id === hoverTarget.corner)?.top ?? '50%',
            width: 10,
            height: 10,
            transform: 'translate(-50%, -50%) translateZ(38px)',
            borderRadius: 2,
            border: '1.5px solid color-mix(in srgb, var(--color-accent) 88%, white 12%)',
            background: 'color-mix(in srgb, var(--color-accent) 24%, transparent)',
          }}
        />
      ) : null}
    </div>
  );
}

function cubeTransformString(visualAzimuthDelta: number, currentElevation: number): string {
  const visualYawDeg = 38 - (visualAzimuthDelta * 180) / Math.PI;
  const visualPitchDeg =
    -24 + Math.max(-8, Math.min(8, (((currentElevation - 0.45) * 180) / Math.PI) * 0.16));
  return `rotateY(${visualYawDeg}deg) rotateX(${visualPitchDeg}deg)`;
}

function CubeVisualFace({ face, active }: { face: FaceDef; active: boolean }): JSX.Element {
  const bgColor = `color-mix(in srgb, var(--color-surface) ${Math.round((1 - face.shade) * 100)}%, var(--color-foreground) ${Math.round(face.shade * 100)}%)`;
  return (
    <div
      style={{
        position: 'absolute',
        inset: 0,
        transform: face.transform,
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
        background: active
          ? 'color-mix(in srgb, var(--color-accent) 22%, var(--color-surface) 78%)'
          : `linear-gradient(135deg, rgba(255,255,255,0.62), ${bgColor} 50%, ${bgColor})`,
        border: active
          ? '1.5px solid color-mix(in srgb, var(--color-accent) 88%, white 12%)'
          : '1px solid color-mix(in srgb, var(--color-border) 70%, var(--color-foreground) 30%)',
        boxShadow:
          'inset 1px 1px 0 rgba(255,255,255,0.8), inset -1px -1px 0 rgba(15,23,42,0.11)',
        color: 'color-mix(in srgb, var(--color-foreground) 78%, #64748b 22%)',
        fontFamily: 'Arial, Helvetica, sans-serif',
        fontSize: face.id === 'TOP' ? 9 : 10,
        fontWeight: 700,
        letterSpacing: 0,
        lineHeight: 1,
        textShadow: '0 1px 0 rgba(255,255,255,0.7)',
        backfaceVisibility: 'hidden',
        userSelect: 'none',
      }}
    >
      {face.label}
    </div>
  );
}

function CubeVisualEdge({ edge, active }: { edge: EdgeDef; active: boolean }): JSX.Element {
  return (
    <div
      style={{
        position: 'absolute',
        left: `calc(50% - ${edge.width / 2}px)`,
        top: `calc(50% - ${edge.height / 2}px)`,
        width: edge.width,
        height: edge.height,
        transform: edge.transform,
        borderRadius: 2,
        background: active ? 'color-mix(in srgb, var(--color-accent) 20%, transparent)' : 'transparent',
        border: active ? '1.5px solid color-mix(in srgb, var(--color-accent) 88%, white 12%)' : 0,
        backfaceVisibility: 'hidden',
      }}
    />
  );
}

function CubeFace({
  face,
  onClick,
  onHover,
}: {
  face: FaceDef;
  onClick: () => void;
  onHover: (hovered: boolean) => void;
}): JSX.Element {
  const style: CSSProperties = {
    position: 'absolute',
    inset: 0,
