function sideLabelsFromAzimuth(azimuth: number): { left: ViewCubeFace; right: ViewCubeFace } {
  const turns = ((azimuth % (Math.PI * 2)) + Math.PI * 2) % (Math.PI * 2);
  if (turns < Math.PI / 2) return { left: 'FRONT', right: 'RIGHT' };
  if (turns < Math.PI) return { left: 'RIGHT', right: 'BACK' };
  if (turns < (Math.PI * 3) / 2) return { left: 'BACK', right: 'LEFT' };
  return { left: 'LEFT', right: 'FRONT' };
}

function HoverHighlight({
