    'FRONT-RIGHT': [49 - sx, 42, 49 - sx, 84],
    'FRONT-LEFT': [8 - skew, 23, 8 - skew, 63],
  };
  const line = lines[hoverTarget.edge] ?? lines['FRONT-TOP']!;
  return (
    <line
      x1={line[0]}
      y1={line[1]}
      x2={line[2]}
      y2={line[3]}
      stroke="color-mix(in srgb, var(--color-accent) 88%, white 12%)"
      strokeWidth="4"
      strokeLinecap="round"
    />
  );
}

