import {
  type CSSProperties,
  type JSX,
  type KeyboardEvent,
  useCallback,
  useRef,
  useState,
} from 'react';
import { ChevronDown, Home } from 'lucide-react';
import {
  alignmentForPick,
  compassLabelFromAzimuth,
  type ViewCubeAlignment,
  type ViewCubeCorner,
  type ViewCubeEdge,
  type ViewCubeFace,
  type ViewCubePick,
} from './viewCubeAlignment';

export interface ViewCubeProps {
  currentAzimuth: number;
  /** Camera elevation in radians (0 = horizontal, π/2 = straight down). */
  currentElevation: number;
  onPick: (pick: ViewCubePick, alignment: ViewCubeAlignment) => void;
  /** Raw pixel deltas during a drag. Viewport calls rig.orbit(dx, dy). */
  onDrag?: (dxPx: number, dyPx: number) => void;
  className?: string;
}

const STAGE_WIDTH = 94;
const STAGE_HEIGHT = 90;
const DRAG_THRESHOLD_PX = 4;

type HoverTarget =
  | { kind: 'face'; face: ViewCubeFace; area: 'top' | 'left' | 'right' }
  | { kind: 'edge'; edge: ViewCubeEdge }
  | { kind: 'corner'; corner: ViewCubeCorner }
  | null;

interface EdgeDef {
  id: ViewCubeEdge;
  label: string;
  left: number;
  top: number;
  width: number;
  height: number;
}

const ALL_FACES: ViewCubeFace[] = ['FRONT', 'BACK', 'LEFT', 'RIGHT', 'TOP', 'BOTTOM'];

const EDGES: EdgeDef[] = [
  { id: 'FRONT-TOP', label: 'Front top edge', left: 14, top: 23, width: 43, height: 12 },
  { id: 'RIGHT-TOP', label: 'Right top edge', left: 47, top: 23, width: 38, height: 12 },
  { id: 'LEFT-TOP', label: 'Left top edge', left: 8, top: 16, width: 42, height: 12 },
  { id: 'BACK-TOP', label: 'Back top edge', left: 42, top: 9, width: 42, height: 12 },
  { id: 'FRONT-RIGHT', label: 'Front right edge', left: 43, top: 34, width: 14, height: 50 },
  { id: 'FRONT-LEFT', label: 'Front left edge', left: 4, top: 31, width: 14, height: 45 },
  { id: 'BACK-RIGHT', label: 'Back right edge', left: 78, top: 26, width: 14, height: 46 },
  { id: 'BACK-LEFT', label: 'Back left edge', left: 43, top: 7, width: 14, height: 35 },
];

const TOP_CORNERS: { id: ViewCubeCorner; left: string; top: string }[] = [
  { id: 'TOP-NW', left: '22px', top: '23px' },
  { id: 'TOP-NE', left: '72px', top: '24px' },
  { id: 'TOP-SW', left: '29px', top: '48px' },
  { id: 'TOP-SE', left: '74px', top: '49px' },
];

export function ViewCube({
  currentAzimuth,
  currentElevation,
  onPick,
  onDrag,
  className,
}: ViewCubeProps): JSX.Element {
  const initialAzimuthRef = useRef(currentAzimuth);
  const dragRef = useRef({ dragging: false, totalMoved: 0 });
  const suppressNextClickRef = useRef(false);
  const [isDragging, setIsDragging] = useState(false);
  const [hoverTarget, setHoverTarget] = useState<HoverTarget>(null);

  function emit(pick: ViewCubePick): void {
    onPick(pick, alignmentForPick(pick));
  }

  function handleKey(event: KeyboardEvent<HTMLDivElement>): void {
    if (event.key === 'Enter' || event.key === ' ') {
      event.preventDefault();
      emit({ kind: 'home' });
    }
  }

  const handlePointerDown = useCallback(
    (e: React.PointerEvent<HTMLDivElement>) => {
      if (e.button !== 0) return;
      dragRef.current = { dragging: true, totalMoved: 0 };
      setIsDragging(true);
      setHoverTarget(null);
      document.body.style.cursor = 'grabbing';

      const onMove = (ev: PointerEvent) => {
        dragRef.current.totalMoved += Math.abs(ev.movementX) + Math.abs(ev.movementY);
        onDrag?.(ev.movementX, ev.movementY);
      };

      const onUp = () => {
        if (dragRef.current.totalMoved > DRAG_THRESHOLD_PX) suppressNextClickRef.current = true;
        dragRef.current.dragging = false;
        setIsDragging(false);
        setHoverTarget(null);
        document.body.style.cursor = '';
        window.removeEventListener('pointermove', onMove);
        window.removeEventListener('pointerup', onUp);
      };

      window.addEventListener('pointermove', onMove);
      window.addEventListener('pointerup', onUp);
    },
    [onDrag],
  );

  const handleClickCapture = useCallback((e: React.MouseEvent) => {
    if (suppressNextClickRef.current) {
      e.stopPropagation();
      suppressNextClickRef.current = false;
    }
  }, []);

  const visualYaw = currentAzimuth - initialAzimuthRef.current;
  const sideLabels = sideLabelsFromAzimuth(currentAzimuth);
  const stageStyle: CSSProperties = {
    width: STAGE_WIDTH,
    height: STAGE_HEIGHT,
    position: 'relative',
    cursor: isDragging ? 'grabbing' : 'grab',
    zIndex: 2,
  };

  return (
    <div
      data-testid="view-cube"
      role="group"
      aria-label="ViewCube"
      onKeyDown={handleKey}
      className={['group relative flex items-center justify-center', className ?? ''].join(' ')}
      style={{ width: 150, height: 148 }}
    >
      <button
        type="button"
        onClick={() => emit({ kind: 'home' })}
        aria-label="Reset camera to home view"
        title="Home view"
        className="absolute left-1 top-0 flex h-7 w-7 items-center justify-center rounded-sm text-muted transition hover:bg-surface hover:text-foreground focus-visible:outline focus-visible:outline-2 focus-visible:outline-accent"
      >
        <Home size={20} strokeWidth={1.9} aria-hidden="true" />
      </button>

      <ViewCubeCompass currentAzimuth={currentAzimuth} />

      <div
        data-testid="view-cube-stage"
        style={stageStyle}
        onPointerDown={handlePointerDown}
        onClickCapture={handleClickCapture}
        onPointerLeave={() => setHoverTarget(null)}
      >
        <CubeVisual
          visualYaw={visualYaw}
          currentAzimuth={currentAzimuth}
          currentElevation={currentElevation}
          hoverTarget={hoverTarget}
        />

        {[
          { id: 'TOP' as const, area: 'top' as const, left: 18, top: 0, width: 60, height: 36 },
          {
            id: sideLabels.left,
            area: 'left' as const,
            left: 4,
            top: 26,
            width: 45,
            height: 58,
          },
          {
            id: sideLabels.right,
            area: 'right' as const,
            left: 49,
            top: 26,
            width: 41,
            height: 58,
          },
        ].map((face) => (
          <CubeButton
            key={face.id}
            def={face}
            label={`Align camera to ${face.id}`}
            dataAttr="data-face"
            dataValue={face.id}
            onClick={() => emit({ kind: 'face', face: face.id })}
            onHover={(hovered) =>
              setHoverTarget(
                hovered ? { kind: 'face', face: face.id, area: face.area } : null,
              )
            }
          />
        ))}
        {ALL_FACES.filter(
          (face) => face !== 'TOP' && face !== sideLabels.left && face !== sideLabels.right,
        ).map((face) => (
          <button
            key={face}
            type="button"
            onClick={() => emit({ kind: 'face', face })}
            aria-label={`Align camera to ${face}`}
            style={{
              position: 'absolute',
              width: 1,
              height: 1,
              overflow: 'hidden',
              clipPath: 'inset(50%)',
              outline: 'none',
            }}
          />
        ))}
        {EDGES.map((edge) => (
          <CubeButton
            key={edge.id}
            def={edge}
            label={`Align camera to ${edge.id}`}
            dataAttr="data-edge"
            dataValue={edge.id}
            onClick={() => emit({ kind: 'edge', edge: edge.id })}
            onHover={(hovered) => setHoverTarget(hovered ? { kind: 'edge', edge: edge.id } : null)}
          />
        ))}
        {TOP_CORNERS.map((corner) => (
          <button
            key={corner.id}
            type="button"
            onClick={() => emit({ kind: 'corner', corner: corner.id })}
            onPointerEnter={() => setHoverTarget({ kind: 'corner', corner: corner.id })}
            onPointerLeave={() => setHoverTarget(null)}
            aria-label={`Align camera to ${corner.id}`}
            data-corner={corner.id}
            style={{
              position: 'absolute',
              left: corner.left,
              top: corner.top,
              transform: 'translate(-50%, -50%)',
              width: 12,
              height: 12,
              border: 0,
              background: 'transparent',
              cursor: 'pointer',
              padding: 0,
              outline: 'none',
            }}
          />
        ))}
      </div>

      <button
        type="button"
        onClick={() => emit({ kind: 'face', face: 'BOTTOM' })}
        aria-label="Look from below"
        title="Look from below"
        className="absolute right-0 top-[84px] flex h-7 w-7 items-center justify-center rounded-sm text-muted transition hover:bg-surface hover:text-foreground focus-visible:outline focus-visible:outline-2 focus-visible:outline-accent"
      >
        <ChevronDown size={22} strokeWidth={1.8} aria-hidden="true" />
      </button>
    </div>
  );
}

function CubeVisual({
  visualYaw,
  currentAzimuth,
  currentElevation,
  hoverTarget,
}: {
  visualYaw: number;
  currentAzimuth: number;
  currentElevation: number;
  hoverTarget: HoverTarget;
}): JSX.Element {
  const skew = Math.max(-9, Math.min(9, Math.sin(visualYaw) * 9));
  const lift = Math.max(-3, Math.min(3, (currentElevation - 0.45) * 5));
  const labels = sideLabelsFromAzimuth(currentAzimuth);
  const p = {
    top: `47,5 ${88 - skew},23 ${49 - skew * 0.18},42 ${8 - skew},23`,
    front: `${8 - skew},23 ${49 - skew * 0.18},42 ${49 - skew * 0.18},84 ${8 - skew},63`,
    right: `${49 - skew * 0.18},42 ${88 - skew},23 ${88 - skew},64 ${49 - skew * 0.18},84`,
  };
  const centerFront = { x: 28 - skew * 0.55, y: 58 };
  const centerRight = { x: 70 - skew * 0.55, y: 58 };
  const centerTop = { x: 48 - skew * 0.45, y: 25 + lift };

  return (
    <svg
      data-cube-stage="true"
      aria-hidden="true"
      viewBox="0 0 94 90"
      width={STAGE_WIDTH}
      height={STAGE_HEIGHT}
      className="pointer-events-none absolute inset-0 overflow-visible"
      style={{ filter: 'drop-shadow(0 15px 13px rgba(15, 23, 42, 0.22))' }}
    >
      <polygon
        points={p.top}
        fill="color-mix(in srgb, var(--color-surface) 94%, white 6%)"
        stroke="color-mix(in srgb, var(--color-border) 68%, var(--color-foreground) 32%)"
        strokeWidth="1.5"
      />
      <polygon
        points={p.front}
        fill="color-mix(in srgb, var(--color-surface) 87%, var(--color-foreground) 13%)"
        stroke="color-mix(in srgb, var(--color-border) 68%, var(--color-foreground) 32%)"
        strokeWidth="1.5"
      />
      <polygon
        points={p.right}
        fill="color-mix(in srgb, var(--color-surface) 80%, var(--color-foreground) 20%)"
        stroke="color-mix(in srgb, var(--color-border) 68%, var(--color-foreground) 32%)"
        strokeWidth="1.5"
      />
      <HoverHighlight hoverTarget={hoverTarget} p={p} skew={skew} />
      <text
        x={centerTop.x}
        y={centerTop.y}
        textAnchor="middle"
        dominantBaseline="middle"
        transform={`rotate(24 ${centerTop.x} ${centerTop.y})`}
        fill="color-mix(in srgb, var(--color-foreground) 76%, #64748b 24%)"
        fontFamily="Arial, Helvetica, sans-serif"
        fontSize="8.5"
        fontWeight="700"
      >
        TOP
      </text>
      <text
        x={centerFront.x}
        y={centerFront.y}
        textAnchor="middle"
        dominantBaseline="middle"
        fill="color-mix(in srgb, var(--color-foreground) 76%, #64748b 24%)"
        fontFamily="Arial, Helvetica, sans-serif"
        fontSize="8.25"
        fontWeight="700"
      >
        {labels.left}
      </text>
      <text
        x={centerRight.x}
        y={centerRight.y}
        textAnchor="middle"
        dominantBaseline="middle"
        fill="color-mix(in srgb, var(--color-foreground) 76%, #64748b 24%)"
        fontFamily="Arial, Helvetica, sans-serif"
        fontSize="8.25"
        fontWeight="700"
      >
        {labels.right}
      </text>
    </svg>
  );
}

function sideLabelsFromAzimuth(azimuth: number): { left: ViewCubeFace; right: ViewCubeFace } {
  const turns = ((azimuth % (Math.PI * 2)) + Math.PI * 2) % (Math.PI * 2);
  if (turns < Math.PI / 2) return { left: 'FRONT', right: 'RIGHT' };
  if (turns < Math.PI) return { left: 'RIGHT', right: 'BACK' };
  if (turns < (Math.PI * 3) / 2) return { left: 'BACK', right: 'LEFT' };
  return { left: 'LEFT', right: 'FRONT' };
}

function HoverHighlight({
  hoverTarget,
  p,
  skew,
}: {
  hoverTarget: HoverTarget;
  p: { top: string; front: string; right: string };
  skew: number;
}): JSX.Element | null {
  if (!hoverTarget) return null;
  const sx = skew * 0.18;
  if (hoverTarget.kind === 'face') {
    const points =
      hoverTarget.area === 'top' ? p.top : hoverTarget.area === 'right' ? p.right : p.front;
    return (
      <polygon
        points={points}
        fill="color-mix(in srgb, var(--color-accent) 18%, transparent)"
        stroke="color-mix(in srgb, var(--color-accent) 88%, white 12%)"
        strokeWidth="1.7"
      />
    );
  }
  if (hoverTarget.kind === 'corner') {
    const size = 6;
    const cornerPoints: Record<ViewCubeCorner, string> = {
      'TOP-NW': `${8 - skew},23 ${8 - skew + size},20 ${8 - skew + size},26 ${8 - skew + 1},29`,
      'TOP-NE': `${88 - skew},23 ${88 - skew - size},20 ${88 - skew - size},26 ${88 - skew - 1},29`,
      'TOP-SW': `${49 - sx},42 ${49 - sx - size},39 ${49 - sx - size},45 ${49 - sx - 1},48`,
      'TOP-SE': `${49 - sx},42 ${49 - sx + size},39 ${49 - sx + size},45 ${49 - sx + 1},48`,
      'BOTTOM-NW': `${8 - skew},63 ${8 - skew + size},60 ${8 - skew + size},66 ${8 - skew + 1},69`,
      'BOTTOM-NE': `${88 - skew},64 ${88 - skew - size},61 ${88 - skew - size},67 ${88 - skew - 1},70`,
      'BOTTOM-SW': `${49 - sx},84 ${49 - sx - size},81 ${49 - sx - size},87 ${49 - sx - 1},89`,
      'BOTTOM-SE': `${49 - sx},84 ${49 - sx + size},81 ${49 - sx + size},87 ${49 - sx + 1},89`,
    };
    return (
      <polygon
        points={cornerPoints[hoverTarget.corner]}
        fill="color-mix(in srgb, var(--color-accent) 22%, transparent)"
        stroke="color-mix(in srgb, var(--color-accent) 88%, white 12%)"
        strokeWidth="1.5"
      />
    );
  }

  const lines: Partial<Record<ViewCubeEdge, [number, number, number, number]>> = {
    'FRONT-TOP': [8 - skew, 23, 49 - sx, 42],
    'RIGHT-TOP': [49 - sx, 42, 88 - skew, 23],
    'FRONT-RIGHT': [49 - sx, 42, 49 - sx, 84],
    'FRONT-LEFT': [8 - skew, 23, 8 - skew, 63],
  };
  const line = lines[hoverTarget.edge] ?? lines['FRONT-TOP']!;
  return (
    <line
      x1={line[0]}
      y1={line[1]}
      x2={line[2]}
      y2={line[3]}
      stroke="color-mix(in srgb, var(--color-accent) 88%, white 12%)"
      strokeWidth="4"
      strokeLinecap="round"
    />
  );
}

function CubeButton({
  def,
  label,
  dataAttr,
  dataValue,
  onClick,
  onHover,
}: {
  def: { left: number; top: number; width: number; height: number };
  label: string;
  dataAttr: 'data-face' | 'data-edge';
  dataValue: string;
  onClick: () => void;
  onHover: (hovered: boolean) => void;
}): JSX.Element {
  return (
    <button
      type="button"
      onClick={onClick}
      onPointerEnter={() => onHover(true)}
      onPointerLeave={() => onHover(false)}
      aria-label={label}
      {...{ [dataAttr]: dataValue }}
      style={{
        position: 'absolute',
        left: def.left,
        top: def.top,
        width: def.width,
        height: def.height,
        border: 0,
        background: 'transparent',
        cursor: 'grab',
        padding: 0,
        outline: 'none',
      }}
    />
  );
}

function ViewCubeCompass({ currentAzimuth }: { currentAzimuth: number }): JSX.Element {
  const cardinal = compassLabelFromAzimuth(currentAzimuth);

  return (
    <svg
      data-testid="view-cube-compass"
      data-cardinal={cardinal}
      viewBox="0 0 150 148"
      width="150"
      height="148"
      className="pointer-events-none absolute inset-0"
      aria-hidden="true"
    >
      <ellipse
        cx="75"
