      />
      <path
        d="M126 88c-2-4-5-7-9-10"
        fill="none"
        stroke="rgb(100 116 139 / 0.48)"
        strokeWidth="1.4"
        strokeLinecap="round"
      />
      <path d="M34 79l-5 1 3 4" fill="none" stroke="rgb(100 116 139 / 0.62)" strokeWidth="2" />
      <path
        d="M116 79l5 1-3 4"
        fill="none"
        stroke="rgb(100 116 139 / 0.62)"
        strokeWidth="2"
      />
      <text
        x="24"
        y="104"
        textAnchor="middle"
        fontFamily="Arial, Helvetica, sans-serif"
        fontSize="16"
        fontWeight="700"
        fill="rgb(71 85 105 / 0.76)"
      >
        S
      </text>
      <text
        x="126"
