+
+const WIDGET_SIZE = 150;
+const STAGE_SIZE = 104;
+const CUBE_CENTER = { x: STAGE_SIZE / 2, y: 47 };
+const CUBE_SCALE = 29;
+const DRAG_THRESHOLD_PX = 4;
+const MIN_ELEVATION = -Math.PI / 2 + 0.04;
+const MAX_ELEVATION = Math.PI / 2 - 0.04;
