+
+type Vec3 = { x: number; y: number; z: number };
+type Point2 = { x: number; y: number; depth: number };
+
+interface FaceDef {
+  id: ViewCubeFace;
+  vertices: Vec3[];
+  normal: Vec3;
+}
+
+interface ProjectedFace {
+  id: ViewCubeFace;
+  points: Point2[];
+  center: Point2;
+  depth: number;
+  topLabelAngle: number;
+}
+
+const FACES: FaceDef[] = [
+  {
