+      { x: 1, y: 1, z: 1 },
+      { x: -1, y: 1, z: 1 },
+    ],
+  },
+  {
+    id: 'RIGHT',
+    normal: { x: 1, y: 0, z: 0 },
+    vertices: [
+      { x: 1, y: -1, z: 1 },
+      { x: 1, y: -1, z: -1 },
+      { x: 1, y: 1, z: -1 },
