+      emit({ kind: 'home' });
+    }
+  }
+
+  const handlePointerDown = useCallback(
+    (e: ReactPointerEvent<HTMLDivElement>) => {
+      if (e.button !== 0) return;
+      dragRef.current = {
+        dragging: true,
+        startAzimuth: currentAzimuth,
+        startElevation: currentElevation,
+        dx: 0,
+        dy: 0,
+        totalMoved: 0,
+      };
+      setIsDragging(true);
+      setHoverTarget(null);
+      e.currentTarget.setPointerCapture(e.pointerId);
+      document.body.style.cursor = 'grabbing';
+
+      const onMove = (ev: PointerEvent) => {
+        const state = dragRef.current;
+        state.dx += ev.movementX;
+        state.dy += ev.movementY;
+        state.totalMoved += Math.abs(ev.movementX) + Math.abs(ev.movementY);
+        setDragPreview({
+          azimuth: state.startAzimuth - state.dx * 0.012,
+          elevation: clamp(state.startElevation + state.dy * 0.01, MIN_ELEVATION, MAX_ELEVATION),
+        });
