+      style={{ width: WIDGET_SIZE, height: WIDGET_SIZE }}
+    >
+      <button
+        type="button"
+        onClick={() => emit({ kind: 'home' })}
+        aria-label="Reset camera to home view"
+        title="Home view"
+        className="absolute left-1 top-0 flex h-7 w-7 items-center justify-center rounded-sm text-muted transition hover:bg-surface hover:text-foreground focus-visible:outline focus-visible:outline-2 focus-visible:outline-accent"
+      >
+        <Home size={20} strokeWidth={1.9} aria-hidden="true" />
+      </button>
+
+      <ViewCubeCompass currentAzimuth={currentAzimuth} />
+
+      <div
+        data-testid="view-cube-stage"
+        onPointerDown={handlePointerDown}
+        onClickCapture={handleClickCapture}
+        onPointerLeave={() => setHoverTarget(null)}
+        style={{
+          position: 'relative',
+          width: STAGE_SIZE,
+          height: STAGE_SIZE,
+          zIndex: 2,
+          cursor: isDragging ? 'grabbing' : 'grab',
+          touchAction: 'none',
+        }}
+      >
+        <CubeSvg
+          faces={model.faces}
+          edges={model.edges}
+          corners={model.corners}
+          hoverTarget={hoverTarget}
+          onHover={setHoverTarget}
+          onPick={emit}
+        />
+
+        {FACES.map((face) => (
+          <button
+            key={face.id}
+            type="button"
+            onClick={() => emit({ kind: 'face', face: face.id })}
+            aria-label={`Align camera to ${face.id}`}
+            style={visuallyHiddenStyle}
+          />
+        ))}
+        {(Object.keys(EDGE_POINTS) as ViewCubeEdge[]).map((edge) => (
+          <button
+            key={edge}
+            type="button"
+            onClick={() => emit({ kind: 'edge', edge })}
+            aria-label={`Align camera to ${edge}`}
+            style={visuallyHiddenStyle}
+          />
+        ))}
+        {(Object.keys(CORNER_POINTS) as ViewCubeCorner[]).map((corner) => (
+          <button
+            key={corner}
+            type="button"
+            onClick={() => emit({ kind: 'corner', corner })}
+            aria-label={`Align camera to ${corner}`}
+            style={visuallyHiddenStyle}
+          />
+        ))}
+      </div>
+
+      <button
+        type="button"
+        onClick={() => emit({ kind: 'face', face: 'BOTTOM' })}
+        aria-label="Look from below"
+        title="Look from below"
+        className="absolute right-0 top-[84px] flex h-7 w-7 items-center justify-center rounded-sm text-muted transition hover:bg-surface hover:text-foreground focus-visible:outline focus-visible:outline-2 focus-visible:outline-accent"
+      >
+        <ChevronDown size={22} strokeWidth={1.8} aria-hidden="true" />
+      </button>
+    </div>
+  );
+}
+
+function CubeSvg({
+  faces,
+  edges,
+  corners,
+  hoverTarget,
+  onHover,
+  onPick,
+}: {
+  faces: ProjectedFace[];
+  edges: { id: ViewCubeEdge; a: Point2; b: Point2; visible: boolean }[];
+  corners: { id: ViewCubeCorner; point: Point2; visible: boolean }[];
+  hoverTarget: HoverTarget;
+  onHover: (target: HoverTarget) => void;
+  onPick: (pick: ViewCubePick) => void;
+}): JSX.Element {
+  return (
+    <svg
+      data-cube-stage="true"
+      aria-hidden="true"
