+            onPointerLeave={() => onHover(null)}
+            onClick={() => onPick({ kind: 'face', face: face.id })}
+          />
+          {hoverTarget?.kind === 'face' && hoverTarget.face === face.id ? (
+            <polygon
+              points={pointsAttr(insetPolygon(face.points, face.center, 0.95))}
+              fill="rgba(32, 126, 255, 0.13)"
+              stroke="#2f83f7"
+              strokeWidth="1.8"
+              strokeLinejoin="round"
+              pointerEvents="none"
+            />
+          ) : null}
+        </g>
+      ))}
+
+      {faces.map((face) => (
+        <text
+          key={`${face.id}-label`}
+          x={face.center.x}
+          y={face.center.y + 1}
+          textAnchor="middle"
+          dominantBaseline="middle"
+          transform={
+            face.id === 'TOP'
+              ? `rotate(${face.topLabelAngle.toFixed(2)} ${face.center.x.toFixed(2)} ${face.center.y.toFixed(2)})`
+              : undefined
+          }
+          fill="#303744"
+          fontFamily="Arial, Helvetica, sans-serif"
+          fontSize={face.id === 'TOP' ? 10 : 11}
+          fontWeight="700"
+          pointerEvents="none"
+        >
+          {face.id}
+        </text>
+      ))}
+
+      {edges
+        .filter((edge) => edge.visible)
+        .map((edge) => (
+          <g key={edge.id}>
+            <line
+              data-edge={edge.id}
+              x1={edge.a.x}
+              y1={edge.a.y}
+              x2={edge.b.x}
+              y2={edge.b.y}
+              stroke="transparent"
+              strokeWidth="11"
+              strokeLinecap="round"
+              onPointerEnter={() => onHover({ kind: 'edge', edge: edge.id })}
+              onPointerLeave={() => onHover(null)}
+              onClick={() => onPick({ kind: 'edge', edge: edge.id })}
+            />
+            {hoverTarget?.kind === 'edge' && hoverTarget.edge === edge.id ? (
+              <line
+                x1={edge.a.x}
+                y1={edge.a.y}
+                x2={edge.b.x}
+                y2={edge.b.y}
+                stroke="#2f83f7"
+                strokeWidth="4"
+                strokeLinecap="round"
+                pointerEvents="none"
+              />
