function buildProjectedCube(
  azimuth: number,
  elevation: number,
): {
  faces: ProjectedFace[];
  edges: { id: ViewCubeEdge; a: Point2; b: Point2; visible: boolean }[];
  corners: { id: ViewCubeCorner; point: Point2; visible: boolean }[];
} {
  const basis = makeProjectionBasis(azimuth, elevation);
  const visibleFaces = FACES.filter((face) => dot(face.normal, basis.dir) > 0.04)
    .map((face) => {
      const points = face.vertices.map((vertex) => project(vertex, basis));
      const center = averagePoint(points);
      const topEdge = face.id === 'TOP' ? [points[0], points[1]] : [points[0], points[1]];
      return {
        id: face.id,
        points,
        center,
        depth: center.depth,
        topLabelAngle: radiansToDegrees(Math.atan2(topEdge[1].y - topEdge[0].y, topEdge[1].x - topEdge[0].x)),
      };
    })
    .sort((a, b) => a.depth - b.depth);

  const visibleFaceIds = new Set(visibleFaces.map((face) => face.id));
  const edges = (Object.entries(EDGE_POINTS) as [ViewCubeEdge, [Vec3, Vec3]][]).map(([id, edge]) => {
    const a = project(edge[0], basis);
    const b = project(edge[1], basis);
    return { id, a, b, visible: isEdgeVisible(id, visibleFaceIds) };
  });
  const corners = (Object.entries(CORNER_POINTS) as [ViewCubeCorner, Vec3][]).map(([id, point]) => ({
    id,
    point: project(point, basis),
    visible: id.startsWith('TOP') || pointDepth(point, basis) > -0.15,
  }));

  return { faces: visibleFaces, edges, corners };
}

function makeProjectionBasis(
  azimuth: number,
  elevation: number,
): { dir: Vec3; right: Vec3; up: Vec3 } {
  const clampedElevation = clamp(elevation, MIN_ELEVATION, MAX_ELEVATION);
  const cosElevation = Math.cos(clampedElevation);
  const dir = normalize({
    x: Math.sin(azimuth) * cosElevation,
    y: Math.sin(clampedElevation),
    z: Math.cos(azimuth) * cosElevation,
  });
  const worldUp = { x: 0, y: 1, z: 0 };
  let right = cross(worldUp, dir);
  if (length(right) < 0.001) right = { x: 1, y: 0, z: 0 };
  right = normalize(right);
  const up = normalize(cross(dir, right));
  return { dir, right, up };
}

function project(point: Vec3, basis: { dir: Vec3; right: Vec3; up: Vec3 }): Point2 {
  return {
    x: CUBE_CENTER.x + dot(point, basis.right) * CUBE_SCALE,
    y: CUBE_CENTER.y - dot(point, basis.up) * CUBE_SCALE,
    depth: dot(point, basis.dir),
  };
}

function pointDepth(point: Vec3, basis: { dir: Vec3 }): number {
  return dot(point, basis.dir);
}

function isEdgeVisible(edge: ViewCubeEdge, visibleFaces: Set<ViewCubeFace>): boolean {
